import{_ as t,o as d,c as a,a4 as e}from"./chunks/framework.BMymQDdR.js";const m=JSON.parse('{"title":"构建选项","description":"","frontmatter":{},"headers":[],"relativePath":"v3/designer/Build-Options.md","filePath":"zh/v3/designer/Build-Options.md","lastUpdated":1780630099000}'),r={name:"v3/designer/Build-Options.md"},o=e('<h1 id="构建选项" tabindex="-1">构建选项 <a class="header-anchor" href="#构建选项" aria-label="Permalink to &quot;构建选项&quot;">​</a></h1><p>构建选项用于配置项目的编译和打包参数，通过 <strong>设置 &gt; 构建选项</strong>（快捷键 <code>Ctrl+F9</code> / macOS <code>Cmd+F9</code>）打开。</p><p>构建选项分为两个标签页：<strong>基础配置</strong>（编译设置）和<strong>打包配置</strong>（安装包设置）。</p><h2 id="基础配置" tabindex="-1">基础配置 <a class="header-anchor" href="#基础配置" aria-label="Permalink to &quot;基础配置&quot;">​</a></h2><h3 id="目标平台" tabindex="-1">目标平台 <a class="header-anchor" href="#目标平台" aria-label="Permalink to &quot;目标平台&quot;">​</a></h3><p>选择需要编译的目标操作系统，可多选：</p><table tabindex="0"><thead><tr><th>平台</th><th>说明</th><th>默认值</th></tr></thead><tbody><tr><td>windows</td><td>编译 Windows 可执行文件</td><td>开启</td></tr><tr><td>macOS</td><td>编译 macOS 可执行文件</td><td>开启</td></tr><tr><td>linux</td><td>编译 Linux 可执行文件</td><td>开启</td></tr></tbody></table><h3 id="目标架构" tabindex="-1">目标架构 <a class="header-anchor" href="#目标架构" aria-label="Permalink to &quot;目标架构&quot;">​</a></h3><p>选择需要编译的 CPU 架构，可多选：</p><table tabindex="0"><thead><tr><th>架构</th><th>说明</th><th>默认值</th><th>平台限制</th></tr></thead><tbody><tr><td>amd64</td><td>64 位 x86 架构</td><td>开启</td><td>无</td></tr><tr><td>386</td><td>32 位 x86 架构</td><td>开启</td><td>macOS 不支持</td></tr><tr><td>arm64</td><td>64 位 ARM 架构</td><td>开启</td><td>Windows 不支持</td></tr><tr><td>arm</td><td>32 位 ARM 架构</td><td>开启</td><td>Windows 和 macOS 不支持</td></tr><tr><td>loong64</td><td>龙芯 64 位架构</td><td>关闭（暂不可用）</td><td>暂不支持</td></tr></tbody></table><h3 id="ui-框架" tabindex="-1">UI 框架 <a class="header-anchor" href="#ui-框架" aria-label="Permalink to &quot;UI 框架&quot;">​</a></h3><p>选择各平台使用的 UI 渲染框架：</p><table tabindex="0"><thead><tr><th>框架</th><th>说明</th><th>默认值</th><th>备注</th></tr></thead><tbody><tr><td>✱Win32</td><td>Windows 原生 UI 框架</td><td>开启（固定）</td><td>Windows 平台必须启用</td></tr><tr><td>✱Cocoa</td><td>macOS 原生 UI 框架</td><td>开启（固定）</td><td>macOS 平台必须启用</td></tr><tr><td>GTK2</td><td>Linux GTK2 UI 框架</td><td>开启</td><td>适用于 LCL 原生渲染</td></tr><tr><td>GTK3</td><td>Linux GTK3 UI 框架</td><td>视项目而定</td><td>适用于 LCL + WebView/CEF 混合渲染</td></tr></tbody></table><h3 id="输出设置" tabindex="-1">输出设置 <a class="header-anchor" href="#输出设置" aria-label="Permalink to &quot;输出设置&quot;">​</a></h3><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th><th>输入类型</th><th>默认值</th></tr></thead><tbody><tr><td>输出目录</td><td>编译输出文件的存放目录</td><td>文本输入 + 目录选择器</td><td><code>./build</code></td></tr><tr><td>可执行文件名称</td><td>编译生成的可执行文件名</td><td>文本输入</td><td>项目名称</td></tr></tbody></table><h3 id="编译模式" tabindex="-1">编译模式 <a class="header-anchor" href="#编译模式" aria-label="Permalink to &quot;编译模式&quot;">​</a></h3><p>编译模式为单选，二选一：</p><table tabindex="0"><thead><tr><th>模式</th><th>说明</th><th>默认值</th></tr></thead><tbody><tr><td>调试模式 (Debug)</td><td>保留调试信息，不优化，适合开发调试</td><td>默认选中</td></tr><tr><td>发布模式 (Release)</td><td>去除调试信息（<code>-s -w</code>），启用优化（<code>-trimpath</code>），Windows 下隐藏控制台窗口（<code>-H windowsgui</code>）</td><td>-</td></tr></tbody></table><h3 id="cgo-设置" tabindex="-1">CGO 设置 <a class="header-anchor" href="#cgo-设置" aria-label="Permalink to &quot;CGO 设置&quot;">​</a></h3><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th><th>输入类型</th><th>默认值</th></tr></thead><tbody><tr><td>已启用 CGO / 已关闭 CGO</td><td>是否启用 CGO（C 语言调用接口）</td><td>复选框</td><td>启用</td></tr><tr><td>构建其它平台</td><td>关闭 CGO 后，可交叉编译其它平台的可执行文件</td><td>复选框（CGO 启用时禁用）</td><td>关闭</td></tr></tbody></table><p><strong>说明：</strong></p><ul><li>启用 CGO 时只能编译当前平台的可执行文件</li><li>关闭 CGO 后可交叉编译 Windows、Linux、macOS 的可执行文件</li><li>使用 <code>energy build --all</code> 命令时会自动禁用 CGO</li></ul><h3 id="构建参数" tabindex="-1">构建参数 <a class="header-anchor" href="#构建参数" aria-label="Permalink to &quot;构建参数&quot;">​</a></h3><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th><th>输入类型</th><th>默认值</th></tr></thead><tbody><tr><td>构建参数</td><td>传递给 <code>go build</code> 的额外参数</td><td>文本输入</td><td>空</td></tr></tbody></table><p><strong>参数格式示例：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>-tags prod -ldflags &quot;-X main.version=1.0&quot;</span></span></code></pre></div><p>支持的参数类型：</p><ul><li><code>-tags</code> - 构建标签（如 <code>prod</code>、<code>dev</code>）</li><li><code>-ldflags</code> - 链接器标志（如 <code>-s -w</code>）</li></ul><h3 id="反编译保护-开发中" tabindex="-1">反编译保护（开发中） <a class="header-anchor" href="#反编译保护-开发中" aria-label="Permalink to &quot;反编译保护（开发中）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th><th>默认值</th><th>状态</th></tr></thead><tbody><tr><td>代码混淆</td><td>对编译后的二进制进行代码混淆</td><td>关闭</td><td>暂不可用</td></tr><tr><td>禁止调试</td><td>防止对应用程序进行调试</td><td>关闭</td><td>暂不可用</td></tr></tbody></table><h2 id="打包配置" tabindex="-1">打包配置 <a class="header-anchor" href="#打包配置" aria-label="Permalink to &quot;打包配置&quot;">​</a></h2><p>打包配置用于设置安装包的生成参数。详见 <a href="./Package-Release">打包发布</a>。</p><h2 id="各平台输出文件格式" tabindex="-1">各平台输出文件格式 <a class="header-anchor" href="#各平台输出文件格式" aria-label="Permalink to &quot;各平台输出文件格式&quot;">​</a></h2><table tabindex="0"><thead><tr><th>平台</th><th>输出文件格式</th><th>特殊处理</th></tr></thead><tbody><tr><td>Windows</td><td><code>build/&lt;name&gt;.exe</code></td><td>Release 模式自动添加 <code>-H windowsgui</code></td></tr><tr><td>macOS</td><td><code>build/&lt;name&gt;.app</code></td><td>自动创建 <code>.app</code> 包结构</td></tr><tr><td>Linux</td><td><code>build/&lt;name&gt;</code></td><td>Release 模式自动执行 <code>strip</code></td></tr></tbody></table><h2 id="跨平台构建" tabindex="-1">跨平台构建 <a class="header-anchor" href="#跨平台构建" aria-label="Permalink to &quot;跨平台构建&quot;">​</a></h2><p>使用 <code>energy build --all</code> 或关闭 CGO 并勾选&quot;构建其它平台&quot;时，会依次构建以下平台组合：</p><table tabindex="0"><thead><tr><th>目标平台</th><th>目标架构</th></tr></thead><tbody><tr><td>Windows</td><td>amd64, 386</td></tr><tr><td>macOS</td><td>amd64, arm64</td></tr><tr><td>Linux</td><td>amd64, 386, arm, arm64</td></tr></tbody></table><p>跨平台构建的输出文件名自动追加平台和架构后缀，如 <code>myapp_windows_amd64.exe</code>。</p>',38),h=[o];function i(l,n,c,s,b,u){return d(),a("div",null,h)}const g=t(r,[["render",i]]);export{m as __pageData,g as default};
